proof_block:
// The two ensures-conjuncts (one for post1_self_, one for post2_self_) share
// disjoint triggers: each `forall|p|` (or `forall|i|`) only fires on
// `post1_self_.foo(p)` for the r1-run and on `post2_self_.foo(p)` for the
// r2-run, so z3 never instantiates them at the same skolem and never
// concludes pointwise equality between the two post states. Each
// `assert forall ... by {}` below introduces a *fused* trigger that mentions
// both runs, forcing z3 to line up the two ensures at the same `p` (or `i`).
// We then lift the spec-fn pointwise equalities to view-level equalities on
// the underlying `Array<Option<_>, _>` fields by case-splitting on `*_active`
// and using `wf` (specifically `pcid_to_proc_wf` / `ioid_to_proc_wf`), which
// states `*_active(x) <==> *_to_proc_ptr@[x as int].is_Some()`.

// ---- pcid: activity, proc-pointer, per-pcid pagetable mapping ----
assert forall|p: Pcid|
    #![trigger post1_self_.pcid_active(p), post2_self_.pcid_active(p)]
    post1_self_.pcid_active(p) == post2_self_.pcid_active(p) by {};

assert forall|p: Pcid|
    #![trigger post1_self_.pcid_to_proc_ptr(p), post2_self_.pcid_to_proc_ptr(p)]
    post1_self_.pcid_active(p)
        ==> post1_self_.pcid_to_proc_ptr(p) == post2_self_.pcid_to_proc_ptr(p) by {};

assert forall|p: Pcid|
    #![trigger post1_self_.get_pagetable_mapping_by_pcid(p), post2_self_.get_pagetable_mapping_by_pcid(p)]
    post1_self_.pcid_active(p) && p != target_pcid
        ==> post1_self_.get_pagetable_mapping_by_pcid(p)
            == post2_self_.get_pagetable_mapping_by_pcid(p) by {};

// ---- ioid: activity, proc-pointer, per-ioid iommu-table mapping ----
assert forall|i: IOid|
    #![trigger post1_self_.ioid_active(i), post2_self_.ioid_active(i)]
    post1_self_.ioid_active(i) == post2_self_.ioid_active(i) by {};

assert forall|i: IOid|
    #![trigger post1_self_.ioid_to_proc_ptr(i), post2_self_.ioid_to_proc_ptr(i)]
    post1_self_.ioid_active(i)
        ==> post1_self_.ioid_to_proc_ptr(i) == post2_self_.ioid_to_proc_ptr(i) by {};

assert forall|i: IOid|
    #![trigger post1_self_.get_iommu_table_mapping_by_ioid(i), post2_self_.get_iommu_table_mapping_by_ioid(i)]
    post1_self_.ioid_active(i)
        ==> post1_self_.get_iommu_table_mapping_by_ioid(i)
            == post2_self_.get_iommu_table_mapping_by_ioid(i) by {};

// ---- Lift the spec-fn pointwise equalities to seq-view equality on the
// underlying `Array<Option<ProcPtr>, _>` fields. `wf` (via `pcid_to_proc_wf`
// / `ioid_to_proc_wf`) gives `*_active(x) <==> *_to_proc_ptr@[x as int].is_Some()`,
// so for inactive indices both are `None` (equal), and for active indices
// both unwrap to the same value via the pointwise eq above. ----
assert forall|j: int| 0 <= j < PCID_MAX implies
    post1_self_.pcid_to_proc_ptr@[j] == post2_self_.pcid_to_proc_ptr@[j] by {
    let p: Pcid = j as Pcid;
    if post1_self_.pcid_active(p) {
        assert(post2_self_.pcid_active(p));
        assert(post1_self_.pcid_to_proc_ptr@[p as int].is_Some());
        assert(post2_self_.pcid_to_proc_ptr@[p as int].is_Some());
        assert(post1_self_.pcid_to_proc_ptr(p) == post2_self_.pcid_to_proc_ptr(p));
    } else {
        assert(!post2_self_.pcid_active(p));
        assert(post1_self_.pcid_to_proc_ptr@[p as int].is_None());
        assert(post2_self_.pcid_to_proc_ptr@[p as int].is_None());
    }
};
assert(post1_self_.pcid_to_proc_ptr@ =~= post2_self_.pcid_to_proc_ptr@);

assert forall|j: int| 0 <= j < IOID_MAX implies
    post1_self_.ioid_to_proc_ptr@[j] == post2_self_.ioid_to_proc_ptr@[j] by {
    let id: IOid = j as IOid;
    if post1_self_.ioid_active(id) {
        assert(post2_self_.ioid_active(id));
        assert(post1_self_.ioid_to_proc_ptr@[id as int].is_Some());
        assert(post2_self_.ioid_to_proc_ptr@[id as int].is_Some());
        assert(post1_self_.ioid_to_proc_ptr(id) == post2_self_.ioid_to_proc_ptr(id));
    } else {
        assert(!post2_self_.ioid_active(id));
        assert(post1_self_.ioid_to_proc_ptr@[id as int].is_None());
        assert(post2_self_.ioid_to_proc_ptr@[id as int].is_None());
    }
};
assert(post1_self_.ioid_to_proc_ptr@ =~= post2_self_.ioid_to_proc_ptr@);
